                sectionBadge: "TOKEN COMPATIBILITY", sectionHeading: "What Makes a Token Compatible",
                sectionBody: "Any token that implements the ERC-20 standard (transfer, transferFrom, approve, balanceOf, totalSupply) is compatible. Tokens with non-standard fee-on-transfer logic may behave differently and should be tested on Sepolia first.",
                cards: [{ title: "WETH Only — Not Native ETH", body: "Only Wrapped ETH (WETH) can be shielded. Wrap your ETH to WETH first using Uniswap or a DEX, then shield the WETH. Unshielding returns WETH, which you can unwrap in one additional step." }, { title: "USDT and USDC", body: "Tether and USDC are fully compatible. Their fee-on-transfer behavior is standard-compliant. qUSDT and qUSDC are minted at 1:1." }, { title: "DAI and Other DeFi Tokens", body: "DAI, LINK, UNI, AAVE, and all standard ERC-20 tokens can be shielded. Any token listed on Coingecko with a standard ERC-20 interface should work." }, { title: "Test on Sepolia First", body: "For non-standard tokens or first-time use, shield a small amount on Sepolia testnet before shielding on Ethereum mainnet.", linkText: "Network support" }],
                relatedLinks: [{ label: "Shield ERC-20 Tokens" }, { label: "Shield Tokens (How-To)" }, { label: "qToken System" }],
