                sectionBadge: "CONTRACT INTERFACE", sectionHeading: "The Three Core Functions",
                sectionBody: "Every function that moves tokens requires the caller to submit their vault proof. The contract hashes it and compares against the stored hash. Wrong proof triggers an immediate revert with no state change.",
                cards: [{ title: "shield(token, amount, proof)", body: "Deposits an ERC-20 token into the Qrypt-Safe and mints the equivalent qToken to the caller. Requires a valid vault proof hash match.", linkText: "Shield tokens guide" }, { title: "commitTransfer + revealTransfer", body: "Two-phase transfer function. Commit submits a hash. Reveal submits proof and details. The contract verifies and moves qTokens only on a hash match.", linkText: "Commit-reveal scheme" }, { title: "unshield(token, amount, proof)", body: "Burns qTokens and returns the original ERC-20 tokens to the caller. Requires vault proof. Atomic: burn and transfer in one transaction.", linkText: "Burn qTokens" }, { title: "emergencyWithdraw()", body: "Callable after 180 days of inactivity. Returns all tokens without requiring a vault proof. For lost vault proof recovery only.", linkText: "180-day inactivity rule" }],
