                cards: [{ title: "Deposit into Railgun Pool", body: "Your Qrypt-Safe initiates a deposit into the Railgun privacy pool on Ethereum. The deposit is publicly visible, but it is indistinguishable from any other Railgun deposit.", linkText: "Transfer Engine", img: "/images/card-non-custodial.jpg" }, { title: "Pool Obfuscation", body: "Inside the Railgun pool, your deposit joins the anonymity set. Cryptographic proofs confirm the correct amount reaches the recipient without revealing which deposit it came from.", img: "/images/transfer-mev.jpg" }, { title: "Public Relayer Broadcasts", body: "A Railgun public relayer picks up the withdrawal instruction and broadcasts it. You do not need to run or trust any specific relayer. Any relayer in the network can fulfill the request.", img: "/images/card-smart-contract.jpg" }, { title: "Recipient Gets Original Token", body: "The original ERC-20 arrives at the recipient wallet. No on-chain trail connects your Qrypt-Safe address to the destination. The full transfer is complete.", linkText: "Making Transfers", img: "/images/exit-receive.jpg" }],
